/* 알림: 행 추가 */
INSERT INTO NOTIFICATION (
    USR_SN, NTF_TYPE_CD, NTF_DOMAIN_CD, NTF_AUDIENCE_CD,
    NTF_TTL, NTF_CN,
    NTF_REF_TYPE_CD, NTF_REF_SN,
    NTF_EMAIL_STATUS_CD
) VALUES (
    #{usrSn}, #{ntfTypeCd}, #{ntfDomainCd}, #{ntfAudienceCd},
    #{ntfTtl}, #{ntfCn},
    #{ntfRefTypeCd}, #{ntfRefSn},
    #{ntfEmailStatusCd}
)

mapper.select:
/* 알림: 미읽음 개수 */
SELECT COUNT(*)
FROM NOTIFICATION
WHERE USR_SN = #{usrSn}
  AND NTF_READ_YN = 'N'

mapper.update:
/* 알림: 개별 읽음 처리 */
UPDATE NOTIFICATION
SET NTF_READ_YN = 'Y',
    NTF_READ_DT = NOW()
WHERE NTF_SN = #{ntfSn}
  AND USR_SN = #{usrSn}
  AND NTF_READ_YN = 'N'

/* 알림: 전체 읽음 처리 */
UPDATE NOTIFICATION
SET NTF_READ_YN = 'Y',
    NTF_READ_DT = NOW()
WHERE USR_SN = #{usrSn}
  AND NTF_READ_YN = 'N'
